// Changed from Singleton to Scoped: .NET 9 enables ValidateScopes in all
// environments, which rejects resolving scoped IUserService from the root container.
// If singleton caching is required, refactor CacheService to accept IServiceScopeFactory.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// ConfigureHttpMessageHandlerBuilder was removed in .NET 9, and the default
// primary handler is now SocketsHttpHandler (not HttpClientHandler).
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler
    {
        UseCookies = false
    });

